// GENERATED brand artwork for the feature-showcase demo document.
// The mark and banner are rendered from doc/logo.svg / doc/banner.svg
// (rsvg-convert) and base64-embedded so buildDemoPdf stays synchronous
// and asset-free. Regenerate with tool/gen_demo_brand_assets.sh.
import 'dart:convert';
import 'dart:typed_data';

/// 160×160 RGBA PNG of the dart-pdf app mark (doc/logo.svg).
Uint8List demoLogoPng() => base64Decode(_logo);

/// 960×300 RGB PNG of the dart-pdf banner (doc/banner.svg).
Uint8List demoBannerPng() => base64Decode(_banner);

const String _logo = '';

const String _banner = '';
